import{_ as s,o,c as a,ag as i}from"./chunks/framework.BZohXCq9.js";const g=JSON.parse('{"title":"第12章 网络隔离策略","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/12-network-isolation.md","filePath":"chapters/12-network-isolation.md"}'),t={name:"chapters/12-network-isolation.md"};function n(r,e,d,l,c,p){return o(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="第12章-网络隔离策略" tabindex="-1">第12章 网络隔离策略 <a class="header-anchor" href="#第12章-网络隔离策略" aria-label="Permalink to &quot;第12章 网络隔离策略&quot;">​</a></h1><blockquote><p>&quot;安全不是一堵墙，而是一系列层层递进的关卡。每一层都假设前一层可能被突破。&quot; —— Bruce Schneier</p></blockquote><p>AI Agent 在沙箱中执行代码时，往往需要访问外部网络——下载依赖包、调用 API、抓取网页。但完全开放的网络等于没有沙箱。OpenSandbox 设计了三层网络隔离架构：Ingress 代理控制入站流量、Egress sidecar 管控出站流量、NetworkPolicy 提供声明式规则模型。本章将逐层剖析这套网络安全体系。</p><h2 id="三层架构总览" tabindex="-1">三层架构总览 <a class="header-anchor" href="#三层架构总览" aria-label="Permalink to &quot;三层架构总览&quot;">​</a></h2><p>OpenSandbox 的网络拓扑呈 &quot;三明治&quot; 结构：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>客户端 → [Ingress Proxy] → 沙箱容器 → [Egress Sidecar] → 外部网络</span></span>
<span class="line"><span>                                ↑</span></span>
<span class="line"><span>                        [NetworkPolicy 规则]</span></span></code></pre></div><p>Ingress 负责将外部请求安全地路由到正确的沙箱实例；Egress 拦截沙箱的出站请求，基于策略决定放行或拒绝；NetworkPolicy 是策略的声明式描述，通过 API 动态下发。三层各司其职，纵深防御。</p><h2 id="ingress-代理-智能路由与沙箱发现" tabindex="-1">Ingress 代理：智能路由与沙箱发现 <a class="header-anchor" href="#ingress-代理-智能路由与沙箱发现" aria-label="Permalink to &quot;Ingress 代理：智能路由与沙箱发现&quot;">​</a></h2><p>Ingress 组件（<code>components/ingress/main.go</code>）是一个基于 Go 实现的 HTTP/WebSocket 反向代理。它的核心职责是将客户端请求路由到正确的沙箱容器内部端口。</p><h3 id="两种路由模式" tabindex="-1">两种路由模式 <a class="header-anchor" href="#两种路由模式" aria-label="Permalink to &quot;两种路由模式&quot;">​</a></h3><p>Ingress 支持两种沙箱寻址方式，通过 <code>GatewayRouteModeConfig</code> 配置：</p><ol><li><strong>Header 路由</strong>：客户端在 HTTP 头中设置 <code>OpenSandbox-Ingress-To</code> 指定目标沙箱 ID，适合 SDK 直连场景。</li><li><strong>URI 路由</strong>：将沙箱 ID 编码在 URL 路径中，适合浏览器直接访问的 GUI Agent 场景（如 VNC、VS Code）。</li></ol><p>为什么需要两种模式？Header 路由对客户端来说最简洁，一个请求头搞定路由；但浏览器访问 WebSocket 或 VNC 时无法自定义请求头，此时 URI 路由就成了必需品。</p><h3 id="沙箱发现机制" tabindex="-1">沙箱发现机制 <a class="header-anchor" href="#沙箱发现机制" aria-label="Permalink to &quot;沙箱发现机制&quot;">​</a></h3><p>Ingress 通过 Kubernetes CRD Watch 机制实时感知沙箱的创建和销毁。<code>components/ingress/pkg/sandbox/</code> 目录下实现了多种 provider：<code>agent_sandbox_provider.go</code> 对接 agent-sandbox CRD，<code>batchsandbox_provider.go</code> 对接 BatchSandbox CRD。<code>factory.go</code> 根据配置的 provider 类型创建对应的实例，并设置 30 秒的重同步周期确保缓存一致性。</p><p>当请求到达时，<code>proxy.go</code> 中的 <code>resolveRealHost()</code> 查询 provider 获取沙箱的实际 IP 地址。如果沙箱不存在返回 404，沙箱未就绪返回 503，其他错误返回 502。这种精确的错误码映射帮助客户端 SDK 做出正确的重试决策。</p><h3 id="websocket-透传" tabindex="-1">WebSocket 透传 <a class="header-anchor" href="#websocket-透传" aria-label="Permalink to &quot;WebSocket 透传&quot;">​</a></h3><p>GUI Agent 场景（VNC 桌面、VS Code 远程开发）依赖 WebSocket 长连接。Ingress 通过检测三个条件来识别 WebSocket 请求：HTTP 方法为 GET、<code>Upgrade</code> 头为 <code>websocket</code>、<code>Connection</code> 头为 <code>Upgrade</code>。识别后自动选择 WebSocket 专用代理，并根据 TLS 状态设置 <code>wss</code> 或 <code>ws</code> 协议。这种透明代理机制使得 GUI Agent 无需感知中间代理层的存在。</p><h3 id="自动续期与健康检查" tabindex="-1">自动续期与健康检查 <a class="header-anchor" href="#自动续期与健康检查" aria-label="Permalink to &quot;自动续期与健康检查&quot;">​</a></h3><p>OSEP-0009 提案引入了自动续期机制：当 Ingress 收到请求时，可选地通过 Redis 发布续期意图（renew intent），通知控制面延长沙箱的生命周期。这解决了一个实际痛点——Agent 正在积极使用沙箱时，不应因为固定超时而被强制回收。<code>/status.ok</code> 端点提供健康检查，供 Kubernetes 的 readiness/liveness 探针使用。</p><h2 id="egress-sidecar-出站流量的守门人" tabindex="-1">Egress Sidecar：出站流量的守门人 <a class="header-anchor" href="#egress-sidecar-出站流量的守门人" aria-label="Permalink to &quot;Egress Sidecar：出站流量的守门人&quot;">​</a></h2><p>Egress sidecar（<code>components/egress/</code>）是网络隔离的核心防线，它以 sidecar 模式运行在沙箱容器的同一网络命名空间中，拦截所有出站 DNS 和 TCP 流量。</p><h3 id="双模式执行" tabindex="-1">双模式执行 <a class="header-anchor" href="#双模式执行" aria-label="Permalink to &quot;双模式执行&quot;">​</a></h3><p>Egress 通过 <code>OPENSANDBOX_EGRESS_MODE</code> 环境变量配置执行模式：</p><ul><li><strong>dns 模式</strong>（默认）：仅通过 DNS 代理实施策略。所有 DNS 查询被 iptables 重定向到本地 15353 端口的 DNS 代理，代理根据白名单决定是否解析。未授权域名的 DNS 查询返回 NXDOMAIN。</li><li><strong>dns+nft 模式</strong>：在 DNS 过滤基础上增加 nftables IP 层防火墙。即使应用程序绕过 DNS（硬编码 IP），nftables 规则也会阻断未授权连接。</li></ul><p>为什么默认只用 DNS 模式？因为大部分场景下 DNS 过滤已经足够——AI Agent 执行的 <code>pip install</code>、<code>npm install</code>、<code>curl</code> 等操作都依赖 DNS 解析。dns+nft 模式需要 <code>CAP_NET_ADMIN</code> 权限和 bridge 网络模式，增加了部署复杂度，适用于对安全要求更高的场景。</p><h3 id="dns-安全加固" tabindex="-1">DNS 安全加固 <a class="header-anchor" href="#dns-安全加固" aria-label="Permalink to &quot;DNS 安全加固&quot;">​</a></h3><p>Egress 的 DNS 代理不仅是一个白名单过滤器，还包含多项安全加固措施：</p><ol><li><strong>系统 DNS 自动白名单</strong>：<code>nameserver.go</code> 中的 <code>AllowIPsForNft()</code> 读取 <code>/etc/resolv.conf</code>，自动将系统 DNS 服务器 IP 加入 nftables 允许集合，确保 DNS 查询链路不被自身防火墙阻断。</li><li><strong>DoT 默认阻断</strong>：<code>nft.go</code> 中 <code>BlockDoT: true</code> 默认阻止 DNS over TLS（端口 853），防止应用通过加密 DNS 绕过策略过滤。</li><li><strong>DoH 可配置阻断</strong>：DNS over HTTPS 的阻断通过环境变量配置，支持按 IP/CIDR 精确设置黑名单。</li><li><strong>本地回环始终允许</strong>：<code>127.0.0.1</code> 始终在白名单中，因为 DNS 代理本身监听在本地。</li></ol><h3 id="nftables-集成" tabindex="-1">nftables 集成 <a class="header-anchor" href="#nftables-集成" aria-label="Permalink to &quot;nftables 集成&quot;">​</a></h3><p>在 dns+nft 模式下，<code>nft.go</code> 中的 <code>setupNft()</code> 函数建立了 &quot;静态策略 + 动态白名单&quot; 的双层防火墙：</p><p>静态策略在初始化时应用，包含所有规则和系统 DNS IP。动态白名单通过回调机制实现——当 DNS 代理成功解析一个域名时，调用 <code>proxy.SetOnResolved()</code> 回调将解析得到的 IP 地址动态添加到 nftables 允许集合中。这意味着只有 DNS 白名单中的域名解析出的 IP 才会被放行，有效阻止了直接 IP 连接的绕过尝试。</p><h2 id="networkpolicy-模型" tabindex="-1">NetworkPolicy 模型 <a class="header-anchor" href="#networkpolicy-模型" aria-label="Permalink to &quot;NetworkPolicy 模型&quot;">​</a></h2><p>Egress 的策略模型简洁而实用：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;defaultAction&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;deny&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;egress&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        {</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;action&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;allow&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;target&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;pypi.org&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">},</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        {</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;action&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;allow&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;target&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;*.github.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><code>defaultAction</code> 支持 <code>allow</code>（允许所有，规则为黑名单）和 <code>deny</code>（拒绝所有，规则为白名单）。Target 支持精确域名（<code>pypi.org</code>）和通配符域名（<code>*.example.com</code>），MVP 阶段不支持 IP/CIDR 规则。</p><p>为什么选择 FQDN 而非 IP？因为 AI Agent 的网络访问模式是面向服务的（<code>pip install</code> 访问 <code>pypi.org</code>，不关心其 IP 是什么），FQDN 规则更直觉、更易维护，且自动适应 CDN IP 变化。</p><h2 id="策略-api-与合并语义" tabindex="-1">策略 API 与合并语义 <a class="header-anchor" href="#策略-api-与合并语义" aria-label="Permalink to &quot;策略 API 与合并语义&quot;">​</a></h2><p><code>policy_server.go</code> 提供了完整的 RESTful API：</p><ul><li><strong>GET /policy</strong>：返回当前策略及执行模式（<code>deny_all</code>/<code>allow_all</code>/<code>enforcing</code>）。</li><li><strong>POST /policy</strong>：完整替换策略；空 body 重置为默认 deny-all。</li><li><strong>PATCH /policy</strong>：增量合并规则，保留已有规则。</li></ul><p>PATCH 的合并语义值得关注：<code>mergeEgressRules()</code> 函数实现了 &quot;新规则优先、同 target 去重（last-writer-wins）、域名小写归一化&quot; 的策略。新添加的规则放在列表前端（更高优先级），相同 target 的旧规则被自动覆盖。<code>mergeKey()</code> 对域名做小写转换，确保 <code>PyPI.org</code> 和 <code>pypi.org</code> 被识别为同一目标。</p><p>所有写操作都通过 <code>sync.Mutex</code> 序列化，避免并发 PATCH 导致的丢失更新问题。Request body 限制为 1MB（<code>io.LimitReader(r.Body, 1&lt;&lt;20)</code>），防止恶意大负载。</p><h2 id="认证机制" tabindex="-1">认证机制 <a class="header-anchor" href="#认证机制" aria-label="Permalink to &quot;认证机制&quot;">​</a></h2><p>Egress API 使用 <code>OPENSANDBOX-EGRESS-AUTH</code> 头传递认证 token。<code>authorize()</code> 方法实现了常量时间比较（<code>subtle.ConstantTimeCompare</code>），防止时序攻击。先检查 token 长度是否一致，再进行逐字节比较。当 token 未配置时，API 无需认证——这是开发环境的便利性让步。</p><h2 id="docker-网络模式的影响" tabindex="-1">Docker 网络模式的影响 <a class="header-anchor" href="#docker-网络模式的影响" aria-label="Permalink to &quot;Docker 网络模式的影响&quot;">​</a></h2><p>Docker 运行时下，网络模式的选择直接影响 Egress 的工作方式。Host 模式下容器共享宿主网络栈，Egress sidecar 无法在独立的网络命名空间中工作；Bridge 模式下每个容器有独立的网络命名空间，Egress sidecar 可以完全控制出站流量。因此，需要 Egress 网络隔离的场景必须使用 bridge 网络模式。这个约束在 <code>server/src/services/docker.py</code> 的网络配置逻辑中得到体现。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><p>OpenSandbox 的网络隔离策略遵循 <strong>纵深防御</strong> 原则：Ingress 代理提供入站路由与访问控制，Egress sidecar 实施出站流量过滤，NetworkPolicy 提供声明式规则管理。三层架构中，Egress 的 DNS 代理 + nftables 双重过滤机制是安全核心，而 FQDN 规则模型、增量策略合并、常量时间认证等设计细节则体现了生产级安全系统的严谨。关键源码路径：<code>components/ingress/main.go</code> 和 <code>components/ingress/pkg/proxy/proxy.go</code>（入站代理）、<code>components/egress/policy_server.go</code>（策略 API）、<code>components/egress/nameserver.go</code>（DNS 白名单）、<code>components/egress/nft.go</code>（nftables 集成）。</p>`,48)])])}const k=s(t,[["render",n]]);export{g as __pageData,k as default};
